  ('IntexGlobal','PS3306','Thunder Cheering Sticks Supporter Gear','thunder-cheering-sticks-supporter-gear-ps3306','Outdoor & Lifestyle','Supporter Gear','The Thunder Cheering Sticks are the perfect way to amplify excitement and show support at sports games, concerts, and events.',250,true,false,'["Durable PE Material: Made from high-quality PE material for long-lasting use and vibrant appearance.", "Inflatable Design: Easy to inflate and use, producing loud clapping sounds to energize any crowd.", "Customizable Surface: Ideal for adding logos, slogans, or team branding for promotional purposes.", "Lightweight and Portable: Convenient to carry and distribute at events or gatherings."]'::jsonb,'[{"name": "Size", "value": "10cm W x 60cm L"}]'::jsonb,'[{"name": "Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps3306/ps3306-blue.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps3306/ps3306-green.webp"}, {"name": "Orange", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps3306/ps3306-orange.webp"}, {"name": "Purple", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps3306/ps3306-purple.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps3306/ps3306-red.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps3306/ps3306-white.webp"}, {"name": "Yellow", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps3306/ps3306-yellow.webp"}]'::jsonb,null,'supplier',true,true,0.64,28,'indent_sea','Intex','https://www.intexglobal.com/product/thunder-cheering-sticks/');
