  ('IntexGlobal','PS3310','Cardboard Clapper Supporter Gear','cardboard-clapper-supporter-gear-ps3310','Outdoor & Lifestyle','Supporter Gear','The Cardboard Clapper is the ultimate cheering prop for sports events, concerts, or parties, combining excitement with vibrant branding opportunities.',1,true,false,'["Lightweight and Durable: Made from sturdy cardboard, perfect for creating noise and lasting through events.", "Customizable Design: Printed in full colour on one side, ideal for showcasing team logos, event themes, or promotional messages.", "Great Gaming Prop: Perfect for cheering on your team, making noise, and showing your support.", "Portable and Easy to Use: Compact and lightweight, making it easy to carry and use at any event."]'::jsonb,'[{"name": "Size", "value": "70cm W x 28.5cm H"}]'::jsonb,'[{"name": "Custom", "hex": "", "image": ""}]'::jsonb,null,'supplier',true,true,null,28,'indent_sea','Intex','https://www.intexglobal.com/product/cardboard-clapper/');
