  ('IntexGlobal','PS4001','Chicago Tote Bag','chicago-tote-bag-ps4001','Bags','Tote Bags','The Chicago Tote Bag is a lightweight, practical solution for events, promotions, or daily use, offering simplicity and versatility in one stylish package.',100,true,false,'["Durable Material: Made from 80gsm non-woven fabric for a sturdy and reliable design.", "Lightweight and Convenient: Its simple, lightweight construction makes it easy to carry anywhere.", "Short Handle Design: Compact handles provide a comfortable grip for effortless portability.", "Spacious Capacity: Large volume ideal for carrying essentials, whether at events or during daily errands.", "Customizable Area: Features a generous 17cm x 17cm print space, perfect for branding or promotional designs.", "Variety of Colors: Available in multiple colors to suit any event or personal preference."]'::jsonb,'[{"name": "Size", "value": "29cm x 34cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps4001/ps4001-black.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps4001/ps4001-green.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps4001/ps4001-navy.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps4001/ps4001-red.webp"}, {"name": "Royal Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps4001/ps4001-royal-blue.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps4001/ps4001-white.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/chicago-tote-bag/');
