  ('IntexGlobal','PS4350','17L Metal Cooler Box Camping & Outdoor','17l-metal-cooler-box-camping-outdoor-ps4350','Outdoor & Lifestyle','Camping & Outdoors','The 17L Metal Cooler Box is the ultimate companion for outdoor gatherings, picnics, or backyard barbecues. Designed to keep drinks cool and ready, this cooler box combines durability, style, and practicality. Note: Cooler boxes do not fall under Free Freight. Please contact us for a quote!',5,true,false,'["Lightweight Aluminum Construction: Sturdy yet easy to transport, with a built-in layer of insulation to keep beverages cool.", "Long-Lasting Cooling: Maintains drink temperatures for up to 24 hours.", "Built-In Bottle Opener: Conveniently attached for easy access during parties or outings.", "Customizable Design: Available in a variety of colours and decorated with a full-colour vinyl decal (note: some artwork may have size restrictions).", "Spacious Capacity: 17L volume, perfect for holding drinks and snacks for a group.", "Please confirm artwork suitability for maximum print size before ordering."]'::jsonb,'[{"name": "Size", "value": "31.5cm W x 43cm H x 23.5cm D"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps4350/ps4350-black.webp"}, {"name": "Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps4350/ps4350-blue.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps4350/ps4350-red.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps4350/ps4350-white.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/17l-metal-cooler-box/');
