  ('IntexGlobal','PS5002','Ox Usb Flash Drive','ox-usb-flash-drive-ps5002','Tech','USB Flash Drives','The Ox USB Flash Drive is a practical and stylish storage solution, ideal for everyday use, corporate gifting, or promotional events. Note : USB prices change frequently. Please contact our sales team for the latest price quote.',1,true,false,'["Standard Plastic Design: Durable plastic body with a sleek silver finish and contrasting color trim.", "Variety of Colors: Choose from a range of vibrant color trims to suit your style or branding needs, with additional colors available upon request.", "Compact and Lightweight: Easy to carry, making it perfect for file storage and transfer on the go.", "Customizable Surface: Ideal for adding logos or designs to create a personalized or branded item.", "Versatile Use: Suitable for work, school, or personal storage needs."]'::jsonb,'[{"name": "Size", "value": "7cm x 2cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5002/ps5002-black.webp"}, {"name": "Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5002/ps5002-blue.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5002/ps5002-green.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5002/ps5002-red.webp"}, {"name": "Yellow", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5002/ps5002-yellow.webp"}]'::jsonb,null,'supplier',true,true,null,28,'indent_sea','Intex','https://www.intexglobal.com/product/ox-usb-flash-drive/');
