  ('IntexGlobal','PS5004','Yak Usb Flash Drive','yak-usb-flash-drive-ps5004','Tech','USB Flash Drives','The Yak USB Flash Drive is a practical and stylish data storage solution, perfect for everyday use, corporate gifting, or promotional events. Note : USB prices change frequently. Please contact our sales team for the latest price quote.',1,true,false,'["Standard Plastic Design: Durable and lightweight, crafted for consistent performance and sleek appearance.", "Compact Dimensions: Measures 6.8cm x 2.3cm x 1.2cm, making it portable and easy to carry in pockets, bags, or on a lanyard.", "Customizable Surface: Ideal for branding with logos or designs to suit promotional needs.", "Versatile Use: Perfect for storing and transferring files for work, school, or personal projects."]'::jsonb,'[{"name": "Size", "value": "6.8cm x 2.3cm x 1.2cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5004/ps5004-black.webp"}, {"name": "Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5004/ps5004-blue.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5004/ps5004-red.webp"}, {"name": "Silver", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5004/ps5004-silver.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5004/ps5004-white.webp"}]'::jsonb,null,'supplier',true,true,null,28,'indent_sea','Intex','https://www.intexglobal.com/product/yak-usb-flash-drive/');
