  ('IntexGlobal','PS500X54','Microfibre Tablet Pouch Tech Accessory','microfibre-tablet-pouch-tech-accessory-ps500x54','Tech','Tech Accessories','Introducing the Microfibre Tablet Pouch – the perfect solution for keeping your tablet safe, clean, and protected. Crafted from soft microfiber, this pouch ensures your device stays free from scratches and smudges while offering a convenient, stylish way to carry it.',250,true,false,'["Microfiber Material: Soft and gentle on your tablet, protecting it from scratches and dust.", "Drawstring Closure: Keeps your tablet securely in place while allowing for easy access.", "Cleans and Protects: Doubles as a cleaning cloth to wipe down your tablet’s screen while storing it.", "Compact and Lightweight: Perfectly sized for most tablets, easy to carry in your bag or backpack.", "Durable Design: Built to withstand everyday use and keep your tablet safe wherever you go."]'::jsonb,'[{"name": "Size", "value": "19.5cm W x 30.5cm H"}]'::jsonb,'[{"name": "Custom", "hex": "", "image": ""}]'::jsonb,null,'supplier',true,true,2.89,28,'indent_sea','Intex','https://www.intexglobal.com/product/microfibre-tablet-pouch/');
