  ('IntexGlobal','PS5052','Acrylic Rollup Beanie Hat Beany','acrylic-rollup-beanie-hat-beany-ps5052','Headwear','Beanies','Introducing our Acrylic Rollup Beanie, designed to keep you stylish and warm during all your cold-weather adventures. Crafted from premium acrylic material, this beanie offers outstanding warmth and comfort, making it an essential for chilly days.',250,true,false,'["Premium Acrylic Construction: Ensures superior warmth and comfort, perfect for cold weather.", "Rollup Design: Provides a customizable fit, allowing you to adjust the beanie for the perfect style and comfort.", "Versatile Styling: The roll-up feature adds a casual yet elegant touch to your outfit.", "Ideal for Outdoor Activities: Perfect for skiing, hiking, exploring the city, or simply running errands in the winter.", "Durable and Long-lasting: Designed for everyday wear and longevity."]'::jsonb,'[{"name": "Size", "value": "Adult"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5052/ps5052-black.webp"}, {"name": "Bottle Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5052/ps5052-bottle-green.webp"}, {"name": "Charcoal", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5052/ps5052-charcoal.webp"}, {"name": "Cream", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5052/ps5052-cream.webp"}, {"name": "Grey", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5052/ps5052-grey.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5052/ps5052-navy.webp"}, {"name": "Pink", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/