  ('IntexGlobal','PS5071','Starling Usb Flash Drive','starling-usb-flash-drive-ps5071','Tech','USB Flash Drives','The Starling USB Flash Drive delivers high performance in a tiny package, making it an ideal choice for portability without compromising functionality. Note : USB prices change frequently. Please contact our sales team for the latest price quote.',1,true,false,'["Compact Size: Measures just 6cm x 2cm, making it perfect for slipping into pockets, wallets, or attaching to lanyards.", "Lightweight Design: Adds virtually no extra weight, ideal for on-the-go use or wearing on a lanyard.", "High Performance: Despite its small size, it offers the same capabilities as standard-sized USB flash drives.", "Customizable Surface: Ideal for branding with logos or designs, making it perfect for promotional purposes.", "Versatile Use: Suitable for work, school, or personal file storage and transfers."]'::jsonb,'[{"name": "Size", "value": "6cm W x 2cm H"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5071/ps5071-black.webp"}, {"name": "Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5071/ps5071-blue.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5071/ps5071-green.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5071/ps5071-red.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5071/ps5071-white.webp"}]'::jsonb,null,'supplier',true,true,null,28,'indent_sea','Intex','https://www.intexglobal.com/product/starling-usb-flash-drive/');
