  ('IntexGlobal','PS5092','Metal Swivel Usb Flash Drive','metal-swivel-usb-flash-drive-ps5092','Tech','USB Flash Drives','The Metal Swivel USB Flash Drive is a sleek and durable storage solution, combining functionality with a premium silver design for a professional touch. Note : USB prices change frequently. Please contact our sales team for the latest price quote.',1,true,false,'["Premium Metal Construction: Crafted from high-quality silver metal for durability and a modern, polished look.", "Swivel Design: Protects the USB connector when not in use, ensuring long-lasting functionality.", "Compact and Portable: Lightweight and easy to carry, perfect for everyday use or on-the-go convenience.", "Customizable Surface: Ideal for laser engraving or printing, making it a standout promotional item or personalized gift.", "Versatile Use: Suitable for work, school, or personal file storage and transfer needs."]'::jsonb,'[{"name": "Size", "value": "5.7cm W x 1.5cm H x 0.8cm L"}]'::jsonb,'[{"name": "Silver", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5092/ps5092-main.webp"}]'::jsonb,null,'supplier',true,true,null,28,'indent_sea','Intex','https://www.intexglobal.com/product/metal-swivel-usb-flash-drive/');
