  ('IntexGlobal','PS5115','Credit Card Flash Drive','credit-card-flash-drive-ps5115','Tech','USB Flash Drives','The Credit Card Flash Drive combines functionality with a slim, modern design, making it an excellent choice for everyday use or promotional purposes. Note : USB prices change frequently. Please contact our sales team for the latest price quote.',1,true,false,'["Unique Credit Card Shape: Slim and lightweight design easily fits into wallets, pockets, or cardholders for ultimate portability.", "Durable Plastic Construction: Made from sturdy plastic for long-lasting use.", "Large Customizable Surface: Perfect for full-color printing or branding, offering maximum visibility for logos or designs.", "Convenient and Functional: Provides ample storage space for work, school, or personal files.", "Promotional Appeal: A stylish and practical giveaway item for events, conferences, or corporate branding."]'::jsonb,'[{"name": "Size", "value": "8.5cm W x 5.5cm H"}]'::jsonb,'[{"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5115/ps5115-white.webp"}]'::jsonb,null,'supplier',true,true,null,28,'indent_sea','Intex','https://www.intexglobal.com/product/credit-card-flash-drive/');
