  ('IntexGlobal','PS5302','Castle Key Drive','castle-key-drive-ps5302','Tech','USB Flash Drives','The Castle Key Drive is a functional and innovative USB flash drive, designed to combine practicality with a sleek, key-shaped design. Note : USB prices change frequently. Please contact our sales team for the latest price quote.',1,true,false,'["Unique Key Shape: Aluminium construction in a stylish key design, perfect for attaching to keyrings for easy portability.", "Durable Aluminium Material: Ensures long-lasting use while maintaining a polished and professional appearance.", "Compact and Lightweight: A convenient USB solution that fits seamlessly into your everyday carry.", "Customizable Surface: Ideal for engraving or printing logos, making it a standout promotional item.", "Versatile Use: Perfect for work, school, or personal file storage and transfers."]'::jsonb,'[{"name": "Size", "value": "5.5cm W x 2.5cm H x 0.2cm L"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5302/ps5302-black.webp"}, {"name": "Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5302/ps5302-blue.webp"}, {"name": "Light Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5302/ps5302-light-blue.webp"}, {"name": "Light Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5302/ps5302-light-green.webp"}, {"name": "Orange", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5302/ps5302-orange.webp"}, {"name": "Pink", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps5302/ps5302-pink.webp"}, {"name": "Purple", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a