  ('IntexGlobal','PS6010','Express Flat Ribbed Lanyard - 20mm','express-flat-ribbed-lanyard-20mm-ps6010','Promotional Giveaways','Lanyards','The 20mm Flat Ribbed Lanyard is a versatile and practical choice for events, workplaces, or promotional needs, delivered with speed and quality.',50,true,false,'["20mm Flat Ribbed Design: Comfortable and durable, providing ample space for branding or personalization.", "Safety Breakaway: Includes a safety breakaway feature for added security and convenience.", "Swivel Clip: Comes with a standard swivel clip for easy attachment of ID badges, keys, or other accessories.", "10 Stocked Colours: Available in a range of vibrant colours to match your branding or event theme.", "Express Turnaround: Transfer prints applied and ready for dispatch in as low as 3 days*."]'::jsonb,'[{"name": "Size", "value": "2cm x 90 cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps6010/ps6010-black.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps6010/ps6010-green.webp"}, {"name": "Light Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps6010/ps6010-light-blue.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps6010/ps6010-navy.webp"}, {"name": "Orange", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps6010/ps6010-orange.webp"}, {"name": "Pink", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps6010/ps6010-pink.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps6010/ps6010-red.webp"}, {"name": "R