  ('IntexGlobal','PS7005','Fabric Covered A5 Notebook','fabric-covered-a5-notebook-ps7005','Office & Desk','Notebooks','The Fabric Covered A5 Notebook is a versatile and elegant choice for organizing your thoughts, notes, or plans, designed with added functionality.',100,true,false,'["Fabric Cover: Offers a sophisticated and tactile finish for a premium look and feel.", "Made with recycled paper for an environmentally friendly choice.", "A5 Size: Compact and portable, perfect for daily use at work, school, or on the go.", "Page Marker Ribbon: Easily keep track of your notes or current page.", "Pen Loop: Conveniently store your pen, ensuring it’s always within reach.", "Elastic Closure: Keeps your notebook securely closed when not in use."]'::jsonb,'[{"name": "Size", "value": "20cm H x 14cm W"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps7005/ps7005-black.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps7005/ps7005-navy.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/fabric-covered-a5-notebook/');
