  ('IntexGlobal','PS7006','Soft Smooth Pu Covered Notebook','soft-smooth-pu-covered-notebook-ps7006','Office & Desk','Notebooks','The Soft Smooth PU Covered Notebook is a perfect combination of style and practicality, ideal for jotting down notes, ideas, or plans with ease.',100,true,false,'["Soft PU Cover: Provides a smooth, elegant finish for a modern and professional look.", "Made with recycled paper for an environmentally friendly choice.", "160 Lined Pages: Offers plenty of space for writing, making it ideal for work, school, or personal use.", "A5 Size: Compact and convenient, perfect for carrying in a bag or briefcase."]'::jsonb,'[{"name": "Size", "value": "14cm W x 21cm H"}]'::jsonb,'[{"name": "Charcoal", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps7006/ps7006-charcoal.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps7006/ps7006-navy.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/soft-smooth-pu-covered-notebook/');
