  ('IntexGlobal','PS7015','A5 Carbon Notebook','a5-carbon-notebook-ps7015','Office & Desk','Notebooks','The A5 Carbon Notebook is a sophisticated choice for professionals, students, or anyone who values quality and style in their stationery.',100,true,false,'["Textured PU and Paper Cover: Offers a premium, durable feel with a stylish textured finish.", "High-Quality Paper: Features 192 recycled cream-coloured lined pages (96 sheets) of premium 100g/m² paper for smooth and enjoyable writing.", "Elegant Black Satin Bookmark Ribbon: Adds a touch of sophistication while helping you keep track of your notes.", "Black Page Edges: Provides a sleek and modern finish, making the notebook stand out.", "A5 Size: Perfectly portable, ideal for work, meetings, or personal use."]'::jsonb,'[{"name": "Size", "value": "21 x 14 x 1.7 cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps7015/ps7015-black.webp"}, {"name": "Grey", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps7015/ps7015-grey.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps7015/ps7015-navy.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/a5-carbon-notebook/');
