  ('IntexGlobal','PS7020','Bamboo Notebook','bamboo-notebook-ps7020','Office & Desk','Notebooks','The Bamboo Notebook is an eco-friendly and stylish choice for capturing your ideas, notes, or plans. Its natural bamboo design adds a touch of sophistication, perfect for professionals, students, or promotional use.',100,true,true,'["A5 Hard Cover: Durable cover made from natural bamboo for a sleek and sustainable finish.", "80 Pages of 70gsm Recycled Paper: Provides ample space for notes, lists, and journaling with a smooth writing surface.", "Eco-Friendly Material: Crafted with sustainability in mind, ideal for environmentally conscious individuals or businesses."]'::jsonb,'[{"name": "Size", "value": "15.5 x 21 x 1.4 cm"}]'::jsonb,'[{"name": "Natural", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps7020/ps7020-main.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/bamboo-notebook/');
