  ('IntexGlobal','PS8330','Bamboo Bar Blade Bottle Opener','bamboo-bar-blade-bottle-opener-ps8330','Barware','Bottle Openers','Introducing the Bamboo Bar Blade, a sleek and sustainable bottle opener made from eco-friendly bamboo. Perfect for both personal use and as a unique gift, this bar blade is ideal for those who value both style and sustainability.',50,true,false,'["Eco-Friendly Bamboo: Made from sustainable bamboo, a natural material that adds a touch of elegance.", "Perfect for Customization: Ideal for digital printing or laser engraving, making it a great option for branding or personalized gifts.", "Natural Material: As bamboo is a natural material, slight variances in color and texture may occur, adding to its unique charm."]'::jsonb,'[{"name": "Size", "value": "4 x 17 x 0.8 cm"}]'::jsonb,'[{"name": "Natural", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps8330/ps8330-main.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/bamboo-bar-blade/');
