  ('IntexGlobal','PS8401','Square Coaster Bottle Opener','square-coaster-bottle-opener-ps8401','Barware','Bottle Openers','Introducing the Square Coaster Bottle Opener, a versatile accessory that combines the convenience of a coaster with the functionality of a bottle opener. Perfect for use at home, the office, or as a promotional gift, this coaster is a must-have for any beverage lover.',50,true,false,'["Plastic Coaster with Built-in Bottle Opener: A 2-in-1 design that combines a coaster and bottle opener for ultimate convenience.", "Non-Slip Bottom: Keeps the coaster securely in place, preventing spills and accidents.", "Customizable for Branding: Ideal for digital or pad printing, making it a great promotional item.", "Available in 6 Colours: Choose from a variety of vibrant colours to match your style or branding."]'::jsonb,'[{"name": "Size", "value": "8.5cm W x 8.5cm H x 0.5cm D"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps8401/ps8401-black.webp"}, {"name": "Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps8401/ps8401-blue.webp"}, {"name": "Orange", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps8401/ps8401-orange.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps8401/ps8401-red.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps8401/ps8401-white.webp"}, {"name": "Yellow", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps8401/ps8401-yellow.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/square-coaster-bottle-opener/');
