  ('IntexGlobal','PS8402','Paddle Shaped Bottle Opener','paddle-shaped-bottle-opener-ps8402','Barware','Bottle Openers','Introducing Paddle Shaped Bottle Opener, designed with a built-in magnet, this practical opener keeps your space tidy while offering a modern, functional design. Perfect for home use, parties, or as a promotional gift, it’s a must-have tool for any beverage enthusiast.',50,true,false,'["Plastic Bottle Opener with Magnet: Conveniently stores on metal surfaces like fridges or grills, ensuring easy access.", "Perfect for Custom Printing: Ideal for digital or pad printing, perfect for branding or personalized gifts.", "Available in 6 Colours: Choose from a range of vibrant colours to suit your style or promotional needs."]'::jsonb,'[{"name": "Size", "value": "10.2 cm L x 4.6 cm W x 0.4 cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps8402/ps8402-black.webp"}, {"name": "Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps8402/ps8402-blue.webp"}, {"name": "Orange", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps8402/ps8402-orange.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps8402/ps8402-red.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps8402/ps8402-white.webp"}, {"name": "Yellow", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps8402/ps8402-yellow.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/paddle-shaped-bottle-opener-2/');
