  ('IntexGlobal','PS9003','Wavy Silicone Phone Wallet Phone Accessory','wavy-silicone-phone-wallet-phone-accessory-ps9003','Tech','Phone Accessories','Introducing the Wavy Silicone Phone Wallet – a sleek and practical solution for keeping your essential cards with you at all times. This silicone wallet securely attaches to the back of any phone, providing easy access to your cards while maintaining a slim profile.',250,true,false,'["3M Adhesive: Strong and secure, sticks to the back of any phone for convenient access", "Card Storage: Holds up to 3 credit cards, a driver''s license, or business cards", "Silicone Material: Soft, durable, and flexible for everyday use", "Compact Design: Keeps your cards organized without adding bulk to your phone."]'::jsonb,'[{"name": "Size", "value": "5.5cm W x 8.5cm H"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps9003/ps9003-black.webp"}, {"name": "Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps9003/ps9003-blue.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps9003/ps9003-green.webp"}, {"name": "Light Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps9003/ps9003-light-green.webp"}, {"name": "Orange", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps9003/ps9003-orange.webp"}, {"name": "Purple", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps9003/ps9003-purple.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps9003/ps9003-red.webp"}, {"name": "White", "hex": "", "image": "https://pub-f