  ('IntexGlobal','PS9004','Phone Wallet Standard No Earbud Phone Accessory','phone-wallet-standard-no-earbud-phone-accessory-ps9004','Tech','Phone Accessories','Introducing the Phone Wallet Standard No Earbud – a versatile and practical accessory that keeps your essentials secure and your phone always ready for use. With a strong adhesive, this wallet easily sticks to the back of your phone and doubles as a stand for hands-free viewing.',250,true,false,'["Strong Adhesive: Securely adheres to the back of your phone, providing easy access to your items", "Tangle-Free Earbud Wrap: Keep your earbuds neatly wrapped around the wallet to avoid tangles", "Card and Cash Storage: Perfect for carrying identification, room keys, business cards, cash, or credit cards", "Phone Stand: Doubles as a vertical or horizontal stand – just push down on the center strip to prop up your phone", "Universal Fit: Fits most smartphones for added convenience and versatility."]'::jsonb,'[{"name": "Size", "value": "6cm W x 10cm H"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps9004/ps9004-black.webp"}, {"name": "Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps9004/ps9004-blue.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps9004/ps9004-green.webp"}, {"name": "Orange", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps9004/ps9004-orange.webp"}, {"name": "Purple", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps9004/ps9004-purple.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps9004/ps9004-red.webp"}, {"name": "White", "h