  ('IntexGlobal','PS9123','Reusable Steel Straw Set Drink Bottle','reusable-steel-straw-set-drink-bottle-ps9123','Drinkware','Drink Bottles','Introducing the Reusable Steel Straw Set, perfect for reducing single-use plastic while enjoying your favorite drinks. This set comes neatly packaged in a poly bag, making it easy to carry and store.',50,true,false,'["Stainless Steel Straw Set: Includes 1 straight straw, 1 bent straw, and 1 cleaning brush for effortless maintenance.", "Convenient Plastic Bag: A compact and durable plastic bag for easy storage and portability.", "Customizable with Sticker: Ideal for branding or personalizing the poly bag with a sticker.", "Dishwasher Safe: Easy to clean, making it a hassle-free, eco-friendly option for daily use."]'::jsonb,'[{"name": "Size", "value": "Pouch: 26 x 7.5 cm, Straw: 0.6 x 21.5 cm"}]'::jsonb,'[{"name": "Clear", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/ps9123/ps9123-main.webp"}]'::jsonb,null,'supplier',true,false,null,5,'local_stock','Intex','https://www.intexglobal.com/product/reusable-steel-straw-set/');
