  ('IntexGlobal','RUKY01','Moulded PVC Custom Keyring','moulded-pvc-custom-keyring-ruky01','Key Rings','Novelty Keyrings','Introducing the Moulded PVC Custom Keyring—Flexible, Durable, and Designed to Stand Out. Add personality to your brand with a fully customisable moulded PVC keyring—crafted to bring logos, mascots, and messages to life in a fun, tactile format that’s built to last.',1,true,false,'["Made from durable and flexible moulded PVC for long-lasting use.", "Custom shapes, colours, and designs bring your brand to life.", "Lightweight and compact—perfect for everyday use or promotional giveaways.", "Soft-touch finish and vibrant colours enhance visual appeal.", "Ideal for events, merchandise, branding campaigns, and retail."]'::jsonb,'[{"name": "Size", "value": "Custom"}]'::jsonb,'[{"name": "Custom", "hex": "", "image": ""}]'::jsonb,null,'supplier',true,true,null,28,'indent_sea','Intex','https://www.intexglobal.com/product/moulded-pvc-custom-keyring/');
