  ('IntexGlobal','STRS02','Round Ball Stress Shape Stress Ball & Toy','round-ball-stress-shape-stress-ball-toy-strs02','Toys & Games','Stress Balls & Toys','The Round Ball Stress Shape is a classic and effective stress-relief tool, designed to help reduce tension while promoting your brand. Made from high-quality squeezable polyurethane foam, this stress ball is lightweight, durable, and available in a variety of vibrant colours, making it a popular promotional giveaway for corporate events, trade shows, and wellness campaigns.',250,true,false,'["High-Quality Polyurethane Foam: Soft, durable, and comfortable to squeeze.", "Round Ball Design: Classic shape that fits perfectly in the hand.", "Helps Relieve Stress & Tension: Ideal for office workers, students, and event attendees.", "Available in Multiple Colours: Matches brand themes and event aesthetics."]'::jsonb,'[{"name": "Size", "value": "6 (w) cm"}]'::jsonb,'[{"name": "Dark Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/strs02/strs02-dark-green.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/strs02/strs02-green.webp"}, {"name": "Navy", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/strs02/strs02-navy.webp"}, {"name": "Orange", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/strs02/strs02-orange.webp"}, {"name": "Purple", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/strs02/strs02-purple.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/strs02/strs02-red.webp"}, {"name": "White", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/strs02/strs02-white.webp"}, {"name": "Yellow", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/strs02/strs02-yellow.webp"}, {"name": "Blue", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/strs02/strs02-blue.webp"}, {"name": "Bottle Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/strs02/strs02-bottle-green.webp"}]'::jsonb,null,'supplier',true,true,0.59,28,'indent_sea','Intex','https://www.intexglobal.com/product/round-ball-stress-shape/');
