  ('IntexGlobal','UMBB01','Beach Umbrella','beach-umbrella-umbb01','Outdoor & Lifestyle','Umbrellas','Stay shaded and cool with our Beach Umbrella , designed for comfort and durability at the beach, park, or backyard. Standing at 94cm in height with a 160cm diameter canopy, it features premium 210D encrypted silver rubber fabric for excellent UPF 50+ sun protection. The two-tone inter-colour canopy adds a vibrant touch, making it both stylish and functional for sunny days outdoors.',1,true,false,'["160cm diameter canopy for wide coverage.", "Sturdy 94cm height design.", "Made from 210D encrypted silver rubber fabric.", "UPF 50+ sun protection.", "Two-tone inter-colour canopy for a stylish look."]'::jsonb,'[{"name": "Size", "value": "94 (h) cm"}]'::jsonb,'[{"name": "Dark Green And Grey", "hex": "#004225", "image": ""}, {"name": "Black", "hex": "#000000", "image": ""}, {"name": "Black And Yellow", "hex": "#000000", "image": ""}, {"name": "Green", "hex": "#009639", "image": ""}, {"name": "Grey", "hex": "#8A8D8F", "image": ""}, {"name": "Light Blue", "hex": "#ADD8E6", "image": ""}, {"name": "Navy", "hex": "#001F3F", "image": ""}, {"name": "Orange", "hex": "#FF6900", "image": ""}, {"name": "Purple", "hex": "#5F259F", "image": ""}, {"name": "Red", "hex": "#C8102E", "image": ""}, {"name": "Red And Yellow", "hex": "#C8102E", "image": ""}, {"name": "Yellow", "hex": "#FFD700", "image": ""}]'::jsonb,null,'supplier',true,true,null,28,'indent_sea','Intex','https://www.intexglobal.com/product/beach-umbrella/');
