  ('IntexGlobal','UMBR01','Bonville Golf Umbrella','bonville-golf-umbrella-umbr01','Outdoor & Lifestyle','Umbrellas','The Bonville Golf Umbrella is a premium-quality, large canopy umbrella, designed for superior durability and all-weather protection. Featuring a strong fibreglass shaft for added strength and flexibility, along with a wooden non-slip handle for a secure and comfortable grip, this umbrella is ideal for golfers, corporate giveaways, and outdoor promotions.',250,true,false,'["Fibreglass Shaft: Ensures durability and wind resistance.", "Large Canopy Coverage: Provides excellent protection from sun and rain.", "Wooden Non-Slip Handle: Offers a secure, ergonomic grip.", "Strong & Sturdy Construction: Built to withstand windy conditions.", "Lightweight & Easy to Carry: Ideal for golf courses, outdoor events, and daily use.", "Custom Branding Available: Can be printed with logos or designs for promotional use."]'::jsonb,'[{"name": "Size", "value": "76 (w) x 20 (h) x 20 (d) cm"}]'::jsonb,'[{"name": "Black", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/umbr01/umbr01-black.webp"}, {"name": "Green", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/umbr01/umbr01-green.webp"}, {"name": "Orange", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/umbr01/umbr01-orange.webp"}, {"name": "Red", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/umbr01/umbr01-red.webp"}, {"name": "Royal", "hex": "", "image": "https://pub-fbec7c9199f04af8ab95a413a4620d37.r2.dev/suppliers/intex/products/_variants/w400/umbr01/umbr01-royal.webp"}]'::jsonb,null,'supplier',true,true,8.82,28,'indent_sea','Intex','https://www.intexglobal.com/product/bonville-golf-umbrella/');
